+default_value = false
+
+[[steps]]
+id = "build"
+operation = "ci.build"
+input = { project = "{{params.env}}" }
+
+[[steps]]
+id = "test"
+operation = "ci.test"
+depends_on = ["build"]
+
+[[steps]]
+id = "deploy"
+operation = "infra.deploy"
+depends_on = ["test"]
+on_error = "retry"
+timeout = 300
+condition = "{{params.dry_run}} == false"
+
+[[steps]]
+id = "notify"
+operation = "slack.send"
+depends_on = ["deploy"]
+on_error = "skip"
+"#;
+        let def = parse_pipeline_toml(toml).unwrap();
